html.body:
anvas id="c" width="180" height="180">

const c = document.getElementById('c');
const ctx = c.getContext('2d');

// Fondo redondeado azul oscuro
ctx.beginPath();
ctx.roundRect(0, 0, 180, 180, 36);
ctx.fillStyle = '#1a1a2e';
ctx.fill();

// Estilo líneas
ctx.strokeStyle = 'white';
ctx.lineWidth = 8;
ctx.lineCap = 'round';

// Círculo izquierda
ctx.beginPath(); ctx.arc(45, 95, 18, 0, Math.PI*2); ctx.stroke();
// Línea izq-centro
ctx.beginPath(); ctx.moveTo(63, 95); ctx.lineTo(72, 95); ctx.stroke();
// Círculo centro
ctx.beginPath(); ctx.arc(90, 95, 18, 0, Math.PI*2); ctx.stroke();
// Línea centro-der
ctx.beginPath(); ctx.moveTo(108, 95); ctx.lineTo(117, 95); ctx.stroke();
// Círculo derecha
ctx.beginPath(); ctx.arc(135, 95, 18, 0, Math.PI*2); ctx.stroke();

// Cadena lateral (grupo R aminoácido)
ctx.beginPath(); ctx.moveTo(90, 77); ctx.lineTo(90, 55); ctx.stroke();
// Punto superior
ctx.beginPath(); ctx.arc(90, 46, 10, 0, Math.PI*2);
ctx.fillStyle = 'white'; ctx.fill();
